(8, 'hero', 'Elegance in Every Stitch', 'Curated Fashion for the Modern Soul', NULL, 'https://placehold.co/1500x500/333/fff?text=About+Hero', 0, 1),
(9, 'content', 'Our Story', 'Redefining Luxury Since 2024', 'Prince Garments was born from a passion for timeless style and uncompromising quality. We believe that fashion is not just about what you wear, but how it makes you feel. Every piece in our collection is handpicked to ensure it meets our high standards of craftsmanship. From breathable fabrics to exquisite stitching, we pay attention to the details that matter.', 'https://placehold.co/800x600/e9ecef/333?text=Our+Story', 1, 1),
(10, 'content', 'Sustainable Fashion', 'Conscious choices for a better future', 'We are committed to sustainability. Our materials are sourced responsibly, ensuring fair wages and safe working conditions for all artisans involved. We believe in slow fashion—creating durable pieces that last for years, reducing waste and environmental impact. Join us in making a positive difference, one garment at a time.', 'https://placehold.co/800x600/e9ecef/333?text=Sustainability', 2, 1),
(11, 'value', 'Premium Quality', 'fa-star', 'We use only the finest materials sourced globally.', '', 3, 1),
(12, 'value', 'Community First', 'fa-users', 'Our customers are at the heart of everything we do.', '', 4, 1),
(13, 'value', 'Eco-Friendly', 'fa-leaf', 'Dedicated to reducing our environmental footprint.', '', 5, 1);

