INSERT INTO `ai_faqs` (`id`, `question`, `answer`, `category`, `order`, `active`) VALUES
(1, 'How accurate are the AI size recommendations?', 'Our AI size recommendations have a 95% accuracy rate based on customer feedback. The system improves over time as it learns from more data.', 'Size Recommendations', 1, 1),
(2, 'Is my data safe when using AI features?', 'Absolutely! We use industry-standard encryption and never share your personal data with third parties. All AI processing is done securely on our servers.', 'Privacy', 2, 1),
(3, 'Can I disable AI features?', 'Yes, you can disable AI features anytime from your account settings. However, you\'ll miss out on personalized recommendations and smart features.', 'Settings', 3, 1),
(4, 'How does the virtual try-on work?', 'Upload a full-body photo, and our AI will map the clothing onto your image using advanced computer vision. It takes into account your body shape and proportions for realistic results.', 'Virtual Try-On', 4, 1);

