(1, 'AI-Powered Size Recommendations', 'Get personalized size recommendations based on your measurements and previous purchases. Our AI analyzes thousands of fit data points to suggest the perfect size for you.', 'fa-magic', NULL, NULL, 1, 1),
(2, 'Smart Style Suggestions', 'Discover outfits that match your style preferences. Our AI learns from your browsing history and suggests complementary items to complete your look.', 'fa-lightbulb-o', NULL, NULL, 2, 1),
(3, 'Virtual Try-On', 'See how clothes look on you before buying. Upload your photo and our AI will show you how different outfits would look on your body type.', 'fa-camera', NULL, NULL, 3, 1),
(4, 'Price Drop Alerts', 'Never miss a deal! Our AI tracks price changes and notifies you when items on your wishlist go on sale.', 'fa-bell', NULL, NULL, 4, 1);

