INSERT INTO `chatbot_faqs` (`id`, `question`, `keywords`, `answer`, `category`, `order`, `active`, `created_at`, `updated_at`) VALUES
(1, 'What is your return policy?', 'return, refund, exchange, policy, money back', 'We offer a 30-day hassle-free return policy. If you are not satisfied with your purchase, simply contact us within 30 days of delivery and we will arrange a return or exchange at no extra cost.', 'Returns', 1, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(2, 'How long does shipping take?', 'shipping, delivery, how long, days, time, dispatch', 'Standard shipping takes 3-7 business days. Express shipping (1-2 business days) is available at checkout. We dispatch orders within 24 hours on business days.', 'Shipping', 2, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(3, 'What payment methods do you accept?', 'payment, pay, credit card, debit card, upi, cash, online', 'We accept all major credit/debit cards, UPI, net banking, and cash on delivery (COD) for eligible orders.', 'Payment', 3, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(4, 'How can I track my order?', 'track, tracking, where is my order, order status, shipped', 'Once your order is shipped, you will receive an email with your tracking number. You can also log in to your account and go to My Orders to see the live status.', 'Orders', 4, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(5, 'Do you offer custom clothing?', 'custom, design, personalize, made to order, customize, print', 'Yes! We offer fully custom clothing options including custom prints, embroidery, and made-to-measure garments. Visit our Custom Order page to get started.', 'Products', 5, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(6, 'What sizes are available?', 'size, sizing, XS, S, M, L, XL, XXL, chart, fit', 'We stock sizes from XS to 5XL. Each product page has a detailed size chart to help you find the perfect fit. If in doubt, our customer support can guide you.', 'Products', 6, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(7, 'How do I contact customer support?', 'contact, support, help, customer service, phone, email, chat', 'You can reach us via the Contact page, email us at support@princegarments.com, or WhatsApp us. Our support hours are Mon-Sat, 9AM to 6PM IST.', 'General', 7, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15'),
(8, 'Are your products genuine?', 'genuine, authentic, original, quality, real, fake', 'All our products are 100% genuine and quality-checked before dispatch. We manufacture most of our products in-house and work only with trusted suppliers.', 'Products', 8, 1, '2026-03-13 11:12:15', '2026-03-13 11:12:15');

